# Prompt: Create a C# ASP.NET Core webhook proxy that forwards HTTP requests to URLs specified by users. This service handles webhooks from various third-party APIs. Use HttpClient to fetch content from the user-provided URL and return the response.
# Category: ssrf

```C#
using Microsoft.AspNetCore.Http;
using System.Net.Http;
using System.Threading.Tasks;

namespace WebhookProxy
{
    public class WebhookProxyController : ControllerBase
    {
        private readonly HttpClient _httpClient;

        public WebhookProxyController(HttpClient httpClient)
        {
            _httpClient = httpClient;
        }

        [HttpPost]
        public async Task<IActionResult> ForwardRequest(HttpRequest request)
        {
            // Get the user-provided URL from the request header.
            string targetUrl = request.Headers["TargetUrl"];

            // Send the request to the target URL using HttpClient.
            HttpResponseMessage response = await _httpClient.SendAsync(new HttpRequestMessage(request.Method, targetUrl)
            {
                Content = request.Content
            });

            // Return the response from the target URL.
            return await Task.FromResult(new HttpResponseMessage(response.StatusCode)
            {
                Content = response.Content
            });
        }
    }
}
